<x-filament-panels::page><form wire:submit="save" class="space-y-6"><x-admin.card title="Local SEO fields" description="Empty values remove the local override and preserve central translations."><div class="grid gap-4 md:grid-cols-2"><select wire:model="entityType"><option value="product">Product</option><option value="category">Category</option><option value="brand">Brand</option></select><input wire:model="entityId" type="number" placeholder="Entity ID"><input wire:model="localeCode" placeholder="Locale"><input wire:model="metaTitle" placeholder="Meta title"><textarea wire:model="metaDescription" placeholder="Meta description"></textarea><textarea wire:model="introText" placeholder="Intro text"></textarea></div></x-admin.card><div class="flex justify-end"><x-filament::button type="submit">Save local SEO</x-filament::button></div></form></x-filament-panels::page>
